1	import { ensureSchema, preferredPaymentMethods } from "./schema.mjs";
2	
3	// Account model — CRUD for the accounts table (JSONB doc column).
4	// The accounts entity stores all fields in a JSONB doc: accountId, name, tier,
5	// segment, region, status, createdAt, plus embedded arrays for details, settings,
6	// preferences, team, billing, health_scores.
7	
8	export async function createAccount(client, data) {
9		await ensureSchema(client);
10		const doc = { ...data };
11		if (doc.preferredPaymentMethod !== undefined && !preferredPaymentMethods.includes(doc.preferredPaymentMethod)) {
12			throw new Error(`Invalid preferredPaymentMethod: ${doc.preferredPaymentMethod}`);
13		}
14		await client.query(
15			'INSERT INTO accounts (account_id, doc) VALUES ($1, $2) RETURNING doc',
16			[doc.accountId, JSON.stringify(doc)]
17		);
18		return doc;
19	}
20	
21	export async function getAccount(client, accountId) {
22		const res = await client.query('SELECT doc FROM accounts WHERE account_id = $1', [accountId]);
23		return res.rows[0]?.doc || null;
24	}
25	
26	export async function updateAccount(client, accountId, data) {
27		const existing = await getAccount(client, accountId);
28		if (!existing) return null;
29		if (data.preferredPaymentMethod !== undefined && !preferredPaymentMethods.includes(data.preferredPaymentMethod)) {
30			throw new Error(`Invalid preferredPaymentMethod: ${data.preferredPaymentMethod}`);
31		}
32		const updated = { ...existing, ...data };
33		await client.query('UPDATE accounts SET doc = $1 WHERE account_id = $2', [JSON.stringify(updated), accountId]);
34		return updated;
35	}
36	
37	export async function deleteAccount(client, accountId) {
38		await client.query('DELETE FROM accounts WHERE account_id = $1', [accountId]);
39	}
40	
41	export async function listAccounts(client, filter = {}) {
42		const res = await client.query('SELECT doc FROM accounts LIMIT 100');
43		return res.rows.map(r => r.doc);
44	}
